// Helper para correlación recuperación-performance
// Se usará en renderStats() para gráficas
function getWhoopCorrelationData() {
  return WHOOP_SESSIONS.map(s => ({
    date: s.date,
    recovery: s.recovery_score,
    hrv: s.hrv,
    calories: s.calories_burned,
    strain: s.strain_score,
    sleep: s.sleep_hours
  }));
}

